import React, { useMemo, useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:4000";

type RiskScore = "LOW" | "SUSPICIOUS" | "HIGH";
type Decision = "ALLOW" | "STEP_UP" | "BLOCK";
type View = "verify" | "history" | "docs" | "features" | "pricing" | "apikey";

interface VerifyResult {
  phone: string;
  number_verified: boolean;
  sim_swap_recent: boolean;
  device_active: boolean;
  location_match: boolean;
  risk_score: RiskScore;
  decision: Decision;
  timestamp: string;
}

interface ApiKeyResponse {
  key: string;
  plan: "STARTER" | "GROWTH" | "ENTERPRISE";
  owner: string;
  created_at: string;
}

const decisionText: Record<Decision, string> = {
  ALLOW: "Approve transaction",
  STEP_UP: "Ask for step-up verification",
  BLOCK: "Block and alert fraud team",
};

const navItems: Array<{ id: View; label: string }> = [
  { id: "verify", label: "Fraud Checker" },
  { id: "history", label: "Check History" },
  { id: "docs", label: "API Docs" },
  { id: "features", label: "Features" },
  { id: "pricing", label: "Pricing" },
  { id: "apikey", label: "Get API Key" },
];

const demoCases = [
  { phone: "08011111111", hint: "Safe user", tone: "LOW" as RiskScore },
  { phone: "08022222222", hint: "SIM swap + location", tone: "HIGH" as RiskScore },
  { phone: "08033333333", hint: "Inactive device", tone: "SUSPICIOUS" as RiskScore },
];

function riskBadge(score: RiskScore) {
  if (score === "LOW") return "bg-emerald-500/15 text-emerald-300 border-emerald-500/40";
  if (score === "SUSPICIOUS") return "bg-amber-500/15 text-amber-300 border-amber-500/40";
  return "bg-rose-500/15 text-rose-300 border-rose-500/40";
}

export default function App() {
  const [view, setView] = useState<View>("verify");
  const [phone, setPhone] = useState("08033333333");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [result, setResult] = useState<VerifyResult | null>(null);
  const [history, setHistory] = useState<VerifyResult[]>([]);
  const [stats, setStats] = useState<{ total: number; safe: number; suspicious: number; high: number }>({
    total: 0,
    safe: 0,
    suspicious: 0,
    high: 0,
  });

  const [ownerName, setOwnerName] = useState("");
  const [companyName, setCompanyName] = useState("");
  const [plan, setPlan] = useState<"STARTER" | "GROWTH" | "ENTERPRISE">("STARTER");
  const [apiKeyPayload, setApiKeyPayload] = useState<ApiKeyResponse | null>(null);
  const [apiKeyLoading, setApiKeyLoading] = useState(false);
  const [apiKeyError, setApiKeyError] = useState("");

  const healthMessage = useMemo(() => {
    if (!result) return "Run a verification to get fraud decision.";
    if (result.decision === "ALLOW") return "Customer appears safe. Continue normally.";
    if (result.decision === "STEP_UP") return "Suspicious pattern. Trigger additional identity proof.";
    return "High fraud signal. Block action and investigate.";
  }, [result]);

  async function verifyUser(targetPhone: string) {
    if (!targetPhone.trim()) {
      setError("Please enter a phone number.");
      return;
    }

    try {
      setError("");
      setIsLoading(true);
      const res = await axios.post<VerifyResult>(`${API_URL}/verify-user`, {
        phone: targetPhone,
      });
      const payload = res.data;
      setResult(payload);
      setHistory((prev) => [payload, ...prev].slice(0, 20));
      setStats((prev) => ({
        total: prev.total + 1,
        safe: prev.safe + (payload.risk_score === "LOW" ? 1 : 0),
        suspicious: prev.suspicious + (payload.risk_score === "SUSPICIOUS" ? 1 : 0),
        high: prev.high + (payload.risk_score === "HIGH" ? 1 : 0),
      }));
    } catch {
      setError("Unable to reach backend. Start API server on localhost:4000.");
    } finally {
      setIsLoading(false);
    }
  }

  async function generateApiKey() {
    if (!ownerName.trim() || !companyName.trim()) {
      setApiKeyError("Name and company are required.");
      return;
    }

    try {
      setApiKeyError("");
      setApiKeyLoading(true);
      const res = await axios.post<ApiKeyResponse>(`${API_URL}/api-keys`, {
        owner: ownerName.trim(),
        company: companyName.trim(),
        plan,
      });
      setApiKeyPayload(res.data);
    } catch {
      setApiKeyError("Could not create API key. Ensure backend is running.");
    } finally {
      setApiKeyLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100">
      <div className="mx-auto flex w-full max-w-7xl flex-col lg:flex-row">
        <aside className="border-b border-slate-800 bg-slate-900/70 px-4 py-4 lg:min-h-screen lg:w-72 lg:border-b-0 lg:border-r lg:px-5 lg:py-6">
          <div className="mb-5 rounded-xl border border-emerald-500/40 bg-emerald-500/10 px-3 py-2">
            <p className="text-sm font-semibold text-emerald-300">Fraud Checker</p>
            <p className="text-xs text-emerald-200/80">Hackathon demo mode</p>
          </div>

          <p className="mb-2 text-[11px] uppercase tracking-[0.2em] text-slate-500">Navigation</p>
          <div className="grid grid-cols-2 gap-2 lg:grid-cols-1">
            {navItems.map((item) => (
              <button
                key={item.id}
                className={`rounded-lg border px-3 py-2 text-left text-sm transition ${
                  view === item.id
                    ? "border-cyan-500/60 bg-cyan-500/15 text-cyan-200"
                    : "border-slate-800 bg-slate-900 text-slate-300 hover:border-slate-700 hover:text-white"
                }`}
                onClick={() => setView(item.id)}
              >
                {item.label}
              </button>
            ))}
          </div>

          <div className="mt-6">
            <p className="mb-2 text-[11px] uppercase tracking-[0.2em] text-slate-500">Demo cases</p>
            <div className="space-y-2">
              {demoCases.map((item) => (
                <button
                  key={item.phone}
                  onClick={() => {
                    setView("verify");
                    setPhone(item.phone);
                    void verifyUser(item.phone);
                  }}
                  className="w-full rounded-lg border border-slate-800 bg-slate-900 p-3 text-left transition hover:border-slate-700"
                >
                  <p className="font-mono text-sm text-white">{item.phone}</p>
                  <p className="text-xs text-slate-400">{item.hint}</p>
                  <span className={`mt-2 inline-flex rounded border px-2 py-0.5 text-[10px] ${riskBadge(item.tone)}`}>
                    {item.tone}
                  </span>
                </button>
              ))}
            </div>
          </div>
        </aside>

        <main className="flex-1 px-4 py-5 lg:px-8 lg:py-7">
          <header className="mb-5 flex flex-col gap-3 rounded-2xl border border-slate-800 bg-slate-900/60 p-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <p className="text-xs uppercase tracking-[0.2em] text-cyan-300">POST /verify-user</p>
              <h1 className="text-xl font-bold text-white sm:text-2xl">SIM-Verified Anti-Fraud API</h1>
            </div>
            <div className="rounded-lg border border-slate-700 bg-slate-950 px-3 py-2 text-xs text-slate-300">
              Built for real-world fintech fraud prevention
            </div>
          </header>

          <section className="mb-4 grid grid-cols-2 gap-3 lg:grid-cols-4">
            <StatCard label="Total checks" value={String(stats.total)} />
            <StatCard label="Safe" value={String(stats.safe)} tone="safe" />
            <StatCard label="Suspicious" value={String(stats.suspicious)} tone="warn" />
            <StatCard label="High risk" value={String(stats.high)} tone="danger" />
          </section>

          {view === "verify" && (
            <section className="space-y-4">
              <div className="rounded-2xl border border-slate-800 bg-slate-900/70 p-4">
                <p className="mb-2 text-xs uppercase tracking-[0.2em] text-slate-500">Phone number</p>
                <div className="flex flex-col gap-2 sm:flex-row">
                  <input
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" && !isLoading) void verifyUser(phone);
                    }}
                    className="w-full rounded-xl border border-slate-700 bg-slate-950 px-4 py-3 font-mono text-slate-100 outline-none ring-cyan-500/50 transition focus:border-cyan-500 focus:ring"
                    placeholder="08033333333"
                  />
                  <button
                    onClick={() => void verifyUser(phone)}
                    disabled={isLoading}
                    className="rounded-xl bg-emerald-500 px-6 py-3 font-semibold text-slate-950 transition hover:bg-emerald-400 disabled:cursor-not-allowed disabled:opacity-50"
                  >
                    {isLoading ? "Verifying..." : "Verify"}
                  </button>
                </div>
                {error ? <p className="mt-2 text-sm text-rose-300">{error}</p> : null}
              </div>

              <div className="rounded-2xl border border-amber-500/50 bg-amber-500/10 p-4">
                <div className="flex flex-col justify-between gap-3 sm:flex-row sm:items-center">
                  <div>
                    <p className="text-xs uppercase tracking-[0.2em] text-amber-300">Risk score</p>
                    <p className="text-2xl font-bold text-amber-100">
                      {result ? `${result.risk_score} activity` : "No result yet"}
                    </p>
                    <p className="text-sm text-amber-100/80">{healthMessage}</p>
                  </div>
                  <span className="inline-flex rounded-lg border border-amber-300/50 px-3 py-1 text-xs font-semibold text-amber-200">
                    {result ? result.decision : "STEP_UP"}
                  </span>
                </div>
              </div>

              <div className="grid gap-3 lg:grid-cols-2">
                <CheckCard
                  title="Number verification"
                  passed={result?.number_verified ?? false}
                  passText="MSISDN is valid on network."
                  failText="Number data does not match carrier checks."
                />
                <CheckCard
                  title="SIM swap detection"
                  passed={result ? !result.sim_swap_recent : false}
                  passText="No recent SIM replacement detected."
                  failText="SIM changed recently, strong fraud signal."
                />
                <CheckCard
                  title="Device status"
                  passed={result?.device_active ?? false}
                  passText="Device is active and reachable."
                  failText="Device inactive or unreachable."
                />
                <CheckCard
                  title="Location match"
                  passed={result?.location_match ?? false}
                  passText="Cell and access location are aligned."
                  failText="Location mismatch detected."
                />
              </div>
            </section>
          )}

          {view === "history" && (
            <section className="rounded-2xl border border-slate-800 bg-slate-900/70 p-4">
              <h2 className="mb-3 text-lg font-semibold">Recent verification history</h2>
              {history.length === 0 ? (
                <p className="text-sm text-slate-400">No checks yet. Run verification first.</p>
              ) : (
                <div className="space-y-2">
                  {history.map((item) => (
                    <div
                      key={`${item.phone}-${item.timestamp}`}
                      className="flex flex-col gap-2 rounded-xl border border-slate-800 bg-slate-950 p-3 sm:flex-row sm:items-center sm:justify-between"
                    >
                      <div>
                        <p className="font-mono text-sm">{item.phone}</p>
                        <p className="text-xs text-slate-400">{new Date(item.timestamp).toLocaleString()}</p>
                      </div>
                      <div className="flex gap-2">
                        <span className={`rounded border px-2 py-0.5 text-xs ${riskBadge(item.risk_score)}`}>{item.risk_score}</span>
                        <span className="rounded border border-slate-700 px-2 py-0.5 text-xs text-slate-300">{item.decision}</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>
          )}

          {view === "docs" && (
            <section className="rounded-2xl border border-slate-800 bg-slate-900/70 p-4">
              <h2 className="mb-4 text-lg font-semibold">Quick API docs</h2>
              <div className="space-y-3 text-sm text-slate-300">
                <DocBlock title="POST /verify-user" body={`{ "phone": "08011111111" }`} />
                <DocBlock title="POST /api-keys" body={`{ "owner": "Ada", "company": "PayFlow", "plan": "GROWTH" }`} />
                <div className="rounded-xl border border-slate-800 bg-slate-950 p-3">
                  <p className="font-medium text-white">Decision logic</p>
                  <p className="mt-1 text-slate-400">
                    If SIM swap is recent, block. If any other signal fails, step-up. Else allow.
                  </p>
                </div>
              </div>
            </section>
          )}

          {view === "features" && (
            <section className="grid gap-3 sm:grid-cols-2">
              <FeatureCard title="Real-time network checks" body="Use telco-backed signals instead of OTP-only security." />
              <FeatureCard title="Risk decision engine" body="Return ALLOW, STEP_UP, or BLOCK for every transaction." />
              <FeatureCard title="Simple integration" body="One endpoint to verify number, SIM, device, and location." />
              <FeatureCard title="Audit visibility" body="Track every verification with a timestamp and decision." />
            </section>
          )}

          {view === "pricing" && (
            <section className="grid gap-3 lg:grid-cols-3">
              <PricingCard
                title="Starter"
                price="$0"
                subtitle="Hackathon / MVP"
                bullets={["500 checks/month", "Basic scoring", "Community support"]}
              />
              <PricingCard
                title="Growth"
                price="$99"
                subtitle="Per month"
                bullets={["20k checks/month", "Priority scoring API", "Email support"]}
                featured
              />
              <PricingCard
                title="Enterprise"
                price="Custom"
                subtitle="For banks and large fintechs"
                bullets={["Unlimited checks", "Custom SLA", "Dedicated onboarding"]}
              />
            </section>
          )}

          {view === "apikey" && (
            <section className="rounded-2xl border border-slate-800 bg-slate-900/70 p-4">
              <h2 className="mb-3 text-lg font-semibold">Get API key</h2>
              <p className="mb-4 text-sm text-slate-400">
                Fill details below to create a demo key judges can test immediately.
              </p>

              <div className="grid gap-3 sm:grid-cols-2">
                <input
                  value={ownerName}
                  onChange={(e) => setOwnerName(e.target.value)}
                  placeholder="Owner name"
                  className="rounded-xl border border-slate-700 bg-slate-950 px-3 py-2 outline-none focus:border-cyan-500"
                />
                <input
                  value={companyName}
                  onChange={(e) => setCompanyName(e.target.value)}
                  placeholder="Company name"
                  className="rounded-xl border border-slate-700 bg-slate-950 px-3 py-2 outline-none focus:border-cyan-500"
                />
                <select
                  value={plan}
                  onChange={(e) => setPlan(e.target.value as "STARTER" | "GROWTH" | "ENTERPRISE")}
                  className="rounded-xl border border-slate-700 bg-slate-950 px-3 py-2 outline-none focus:border-cyan-500"
                >
                  <option value="STARTER">Starter</option>
                  <option value="GROWTH">Growth</option>
                  <option value="ENTERPRISE">Enterprise</option>
                </select>
                <button
                  onClick={() => void generateApiKey()}
                  disabled={apiKeyLoading}
                  className="rounded-xl bg-cyan-500 px-4 py-2 font-semibold text-slate-950 transition hover:bg-cyan-400 disabled:opacity-50"
                >
                  {apiKeyLoading ? "Generating..." : "Generate key"}
                </button>
              </div>

              {apiKeyError ? <p className="mt-2 text-sm text-rose-300">{apiKeyError}</p> : null}

              {apiKeyPayload ? (
                <div className="mt-4 rounded-xl border border-emerald-500/40 bg-emerald-500/10 p-3">
                  <p className="text-xs uppercase tracking-[0.2em] text-emerald-300">Generated key</p>
                  <p className="mt-1 break-all rounded bg-slate-950 p-2 font-mono text-sm text-emerald-200">{apiKeyPayload.key}</p>
                  <p className="mt-2 text-xs text-emerald-100/80">
                    Owner: {apiKeyPayload.owner} | Plan: {apiKeyPayload.plan} | Created:{" "}
                    {new Date(apiKeyPayload.created_at).toLocaleString()}
                  </p>
                </div>
              ) : null}
            </section>
          )}

          <footer className="mt-6 rounded-xl border border-slate-800 bg-slate-900/50 px-3 py-2 text-xs text-slate-400">
            Decision recommendation: {result ? decisionText[result.decision] : "Run verification first"}
          </footer>
        </main>
      </div>
    </div>
  );
}

function StatCard({
  label,
  value,
  tone = "default",
}: {
  label: string;
  value: string;
  tone?: "default" | "safe" | "warn" | "danger";
}) {
  const toneMap: Record<string, string> = {
    default: "text-cyan-200 border-cyan-500/30",
    safe: "text-emerald-300 border-emerald-500/30",
    warn: "text-amber-300 border-amber-500/30",
    danger: "text-rose-300 border-rose-500/30",
  };

  return (
    <div className={`rounded-xl border bg-slate-900/60 p-3 ${toneMap[tone]}`}>
      <p className="text-xs uppercase tracking-[0.14em] text-slate-400">{label}</p>
      <p className="mt-1 text-3xl font-bold text-white">{value}</p>
    </div>
  );
}

function CheckCard({
  title,
  passed,
  passText,
  failText,
}: {
  title: string;
  passed: boolean;
  passText: string;
  failText: string;
}) {
  return (
    <div className="rounded-xl border border-slate-800 bg-slate-900/60 p-3">
      <div className="mb-1 flex items-center justify-between gap-2">
        <p className="font-semibold text-white">{title}</p>
        <span
          className={`rounded border px-2 py-0.5 text-xs ${
            passed
              ? "border-emerald-500/40 bg-emerald-500/10 text-emerald-300"
              : "border-rose-500/40 bg-rose-500/10 text-rose-300"
          }`}
        >
          {passed ? "Pass" : "Fail"}
        </span>
      </div>
      <p className="text-sm text-slate-400">{passed ? passText : failText}</p>
    </div>
  );
}

function DocBlock({ title, body }: { title: string; body: string }) {
  return (
    <div className="rounded-xl border border-slate-800 bg-slate-950 p-3">
      <p className="mb-1 font-medium text-white">{title}</p>
      <pre className="overflow-x-auto text-xs text-cyan-200">{body}</pre>
    </div>
  );
}

function FeatureCard({ title, body }: { title: string; body: string }) {
  return (
    <div className="rounded-2xl border border-slate-800 bg-slate-900/70 p-4">
      <p className="text-base font-semibold text-white">{title}</p>
      <p className="mt-1 text-sm text-slate-400">{body}</p>
    </div>
  );
}

function PricingCard({
  title,
  price,
  subtitle,
  bullets,
  featured = false,
}: {
  title: string;
  price: string;
  subtitle: string;
  bullets: string[];
  featured?: boolean;
}) {
  return (
    <div
      className={`rounded-2xl border p-4 ${
        featured
          ? "border-cyan-500/50 bg-cyan-500/10"
          : "border-slate-800 bg-slate-900/70"
      }`}
    >
      <p className="text-sm uppercase tracking-[0.16em] text-slate-400">{title}</p>
      <p className="mt-2 text-3xl font-bold text-white">{price}</p>
      <p className="mt-1 text-sm text-slate-300">{subtitle}</p>
      <ul className="mt-3 space-y-1 text-sm text-slate-300">
        {bullets.map((item) => (
          <li key={item}>- {item}</li>
        ))}
      </ul>
    </div>
  );
}
